function LCityPeopleUnit:RefreshPeopleState()
    if(ModuleCenter.Story:IsNewbieRunning())then
        return
    end
    if(self._objLoaded == false)then
        return
    end
    local isPeople = ModuleCenter.People:CheckIsResident(self._peopleRefId)


    --if(self._isPeople == isPeople)then
    --    return
    --end
    if(isPeople)then
        --居民
        local state = CtrlCenter.City:GetCurTimeState()
        if(state == 1)then
            --睡觉
            self:GotoSleep()

        elseif state == 2 then
            --工作
            self:GotoWork()
        elseif state == 3 then
            --吃饭
            self:GotoEat()
        end

    else
        --流民
        self:GetFsm():ChangeState(CityPeopleFsmState.Birth)
    end
    self._isPeople = isPeople
end
