function LCityPeopleUnit:PlayAni(name,loop,aniCallBack)

    if not self._spineDp or not self._spineDp:IsDpValid() then return end
    if(name == "run")then
        local r = false
        local list = self._spineDp:GetAniNameStrList()
        local count = table.nums(list)
        if(count == 0)then
            r = true
        end
        for i = 1, count do
            if(list[i] == "run")then
                r = true
                break
            end
        end
        if(r == false)then
            name = "move"
        end
    end
    if(self._spineDp)then
        self._spineDp:PlayAnimationInfo(name,loop,nil,aniCallBack)
    end

end


