function LCityPeopleUnit:GotoEat()
    if(ModuleCenter.Story:IsNewbieRunning())then
        --剧情中
        return
    end
    --判断是否在医院，如果在，就不根据时间周期执行逻辑
    local inHospital = CtrlCenter.People:PeopleIsInHospital(self._peopleRefId)
    if(inHospital)then
        return
    end
    --判断是否在技能1002的持续时间内，如果在，就不根据时间周期执行逻辑
    local inSkill = CtrlCenter.People:InSkillTime(1002)
    if(inSkill)then
        self:GotoWork()
        return
    end
    if(self._peopleState == 3)then
        return
    end

    if(self._eatNode ~= nil)then
        print(self._eatNode.name)
    end
    local eatNode = CtrlCenter.City:GetEatNodeName(self._peopleRefId)
    if(eatNode ~= nil)then

        self:SetEatNode(eatNode)
        if(self._peopleBuilding == 2005)then
            self:GetFsm():SetVar("targetPoint",eatNode.position)
            self:GetFsm():ChangeState(CityPeopleFsmState.GoToPoint)
        else
            self:GetFsm():SetVar("GoToBuilding",2005)
            self:GetFsm():SetVar("GotoPoint",nil);
            self:GetFsm():SetVar("Patrol",false);
            self:GetFsm():ChangeState(CityPeopleFsmState.FindPath);
        end

        self._peopleState = 3
    else
    end
end
function LCityPeopleUnit:SetEatNode(nodeName)
    self._eatNode = nodeName
end
function LCityPeopleUnit:GotoWork()
    if(ModuleCenter.Story:IsNewbieRunning())then
        --剧情中
        return
    end
    --判断是否在医院，如果在，就不根据时间周期执行逻辑
    local inHospital = CtrlCenter.People:PeopleIsInHospital(self._peopleRefId)
    if(inHospital)then
        return
    end
    if(self._peopleState == 2 and self._peopleBuilding == ModuleCenter.People:GetPeopleObj(self._peopleRefId).building )then
        return
    end
    if(ModuleCenter.People:GetPeopleObj(self._peopleRefId).building > 0)then
        --有工作,去工作地点
        self:GetFsm():SetVar("GoToBuilding",ModuleCenter.People:GetPeopleObj(self._peopleRefId).building);
        self:GetFsm():SetVar("Patrol",false);
        self:GetFsm():SetVar("GotoPoint",nil);
        self:GetFsm():ChangeState(CityPeopleFsmState.FindPath);
        self._peopleState = 2
        self._peopleBuilding = ModuleCenter.People:GetPeopleObj(self._peopleRefId).building
    else
        local sick = ModuleCenter.People:GetPeopleObj(self._peopleRefId).sick
        if(sick)then
            --生病，工作的时候就去出生点待着
            local pos = Vector3(self._peopleRef.site[1],self._peopleRef.site[2],0)
            self:GetFsm():SetVar("Patrol",false);
            self:GetFsm():SetVar("GoToBuilding",nil);
            self:GetFsm():SetVar("GotoPoint",pos);
            self:GetFsm():ChangeState(CityPeopleFsmState.FindPath);
            self._peopleState = 2
            self._peopleBuilding = 0
            return
        end
        --巡逻,随机一条路
        self:DoPatrol()
    end

end
function LCityPeopleUnit:DoPatrol(setState)
    if(setState == nil)then
        setState = true
    end
    self:GetFsm():SetVar("Patrol",true);
    self:GetFsm():SetVar("GoToBuilding",nil);
    self:GetFsm():SetVar("GotoPoint",nil);
    self:GetFsm():ChangeState(CityPeopleFsmState.FindPath);
    if(setState)then
        self._peopleState = 2
    end
    self._peopleBuilding = ModuleCenter.People:GetPeopleObj(self._peopleRefId).building
end
