--从医院出来
function LCityPeopleUnit:OutHospital(refId)
    if(ModuleCenter.Story:IsNewbieRunning())then
        --剧情中
        return
    end
    --判断是否在技能1002的持续时间内，如果在，就不根据时间周期执行逻辑
    local inSkill = CtrlCenter.People:InSkillTime(1002)
    if(inSkill)then
        self:GotoWork()
        return
    end

    if(refId ~= self._peopleRefId)then
        return
    end
    self:GetFsm():SetVar("GoToBuilding",nil);
    self:GetFsm():SetVar("Patrol",false);
    self:GetFsm():SetVar("GotoPoint",Vector3(self._peopleRef.site[1],self._peopleRef.site[2],0))
    self:GetFsm():ChangeState(CityPeopleFsmState.FindPath);
    self._peopleState = 5;
end
--去医院
--自动寻路到医院
--如果没床位，寻路到出生点
--如果有床位，寻路到医院
function LCityPeopleUnit:GotoHospital()
    if(ModuleCenter.Story:IsNewbieRunning())then
        --剧情中
        return
    end
    local sick = ModuleCenter.People:GetPeopleObj(self._peopleRefId).sick
    if(sick == false)then
        return
    end
    local inHospital = CtrlCenter.People:PeopleIsInHospital(self._peopleRefId)
    local canGoHospital = CtrlCenter.People:PeopleCanGoHospital()
    if(inHospital)then
        if(self._peopleState == 4)then
            return
        end
        --去医院
        self:GetFsm():SetVar("GoToBuilding",2006);
        self:GetFsm():SetVar("Patrol",false);
        self:GetFsm():SetVar("GotoPoint",nil);
        self:GetFsm():ChangeState(CityPeopleFsmState.FindPath);
        self._peopleState = 4;
    else
        if(canGoHospital)then
            if(self._peopleState == 4)then
                return
            end
            --去医院
            self:GetFsm():SetVar("GoToBuilding",2006);
            self:GetFsm():SetVar("Patrol",false);
            self:GetFsm():SetVar("GotoPoint",nil);
            self:GetFsm():ChangeState(CityPeopleFsmState.FindPath);
            self._peopleState = 4;
        else
            --去出生点
            self:GetFsm():SetVar("GoToBuilding",false);
            self:GetFsm():SetVar("Patrol",nil);
            self:GetFsm():SetVar("GotoPoint",Vector3(self._peopleRef.site[1],self._peopleRef.site[2],0))
            self:GetFsm():ChangeState(CityPeopleFsmState.FindPath);
        end
    end
end
function LCityPeopleUnit:GotoSleep()
    if(ModuleCenter.Story:IsNewbieRunning())then
        --剧情中
        return
    end
    --判断是否在医院，如果在，就不根据时间周期执行逻辑
    local inHospital = CtrlCenter.People:PeopleIsInHospital(self._peopleRefId)
    if(inHospital)then
        return
    end
    --判断是否在技能1002的持续时间内，如果在，就不根据时间周期执行逻辑
    local inSkill = CtrlCenter.People:InSkillTime(1002)
    if(inSkill)then
        self:GotoWork()
        return
    end
    if(self._peopleState == 1)then


        return
    end

    local homeList = {}
    for i, v in pairs(GameTable.BuildingRef) do
        if(v.type == 2007)then
            table.insert(homeList,v)
        end
    end
    local count = table.nums(homeList)
    local index = math.random(1,count)
    self:GetFsm():SetVar("GoToBuilding",ModuleCenter.People:GetPeopleObj(self._peopleRefId).house)
    self:GetFsm():SetVar("Patrol",false)
    self:GetFsm():SetVar("GotoPoint",nil);
    self:GetFsm():ChangeState(CityPeopleFsmState.FindPath);
    self._peopleState = 1
end

