function LCityPeopleUnit:ResetPeopleScale()
    if(self._peopleTrans == nil)then
        return
    end
    local ref = GameTable.PeopleRef[self._peopleRefId]

    local scale = 1
    if(checknumber(ref.scale) > 0)then
        scale = ref.scale
    end
    self._peopleTrans.localScale = Vector3(scale,scale,scale)
    if(self._spineDp)then
        self._spineDp:SetScale(1)
    end
end
function LCityPeopleUnit:SetPaths(pathTime,paths)
    self._paths = paths
    self._pathTime = pathTime
    self._pathIndex = 0
    self._pathTotal = #paths
end
function LCityPeopleUnit:DoPathRun(ani)
    local aniName = SpineAniNameEnum.run
    if(ani ~= nil)then
        aniName = ani
    end
    local paths = self._paths
    local pathTime = self._pathTime
    self:StopMove()
    if(pathTime <= 0)then
        local pathData = paths[#paths]
        self:SetPosition(Vector3(pathData.x,pathData.y,0))
        self:SetDirector(pathData.f)
        return
    end
    local dis = 0
    local pos = self:GetPosition()
    local total = 0
    for i, v in ipairs(paths) do
        dis = Vector2.Distance(pos,v)
        total = total + dis
        v.dis = dis
        pos = v
    end
    if(total == 0)then
        local pathData = paths[#paths]
        self:SetPosition(Vector3(pathData.x,pathData.y,0))
        self:SetDirector(pathData.f)
        return
    end
    self._pathDistance = total
    self:PlayAni(aniName,true)
    self:NextPath()
end
function LCityPeopleUnit:NextPath()
    if(self._pathIndex >= self._pathTotal)then
        self:PlayAni(SpineAniNameEnum.idle,true)
        return
    end
    self._pathIndex = self._pathIndex + 1
    local pathData = self._paths[self._pathIndex]
    self:SetDirector(pathData.f)
    local tempPos = Vector3(pathData.x,pathData.y,0)
    local time = pathData.dis * self._pathTime/self._pathDistance
    if(self._cRole == nil)then
        if(self._peopleObj == nil)then
            return
        end
        self._cRole = self._peopleObj:AddComponent(typeOfRoleObject)
        self._cRole.OnMoveEnd = function()
            self:OnMoveEnd()
        end
    end
    if(self._cRole ~= nil)then
        self._cRole:MoveTo(tempPos,time)
        self._cRole.moveType = 0;
        self._cRole.isMoving = true
    end
end

function LCityPeopleUnit:OnMoveEnd()
    self:NextPath()
end
function LCityPeopleUnit:SetDirector(dir)
    if(dir == 0)then
        return
    end
    if(dir < 0)then
        if(self._spineDp)then
            self._spineDp:SetFlipX(true)
        end
    elseif dir > 0 then
        if(self._spineDp)then
            self._spineDp:SetFlipX(false)
        end
    end
end
function LCityPeopleUnit:StopMove()
    if(self._cRole ~= nil)then
        self._cRole.isMoving = false
    end
end
return LCityPeopleUnit;


